```javascript
const input = document.getElementById('compose-input');
const form  = document.getElementById('compose');

// Autoresize: grow with content, max 120px
function autoresize(el) {
  el.style.height = 'auto';
  el.style.height = Math.min(120, el.scrollHeight) + 'px';
}
input.addEventListener('input', () => autoresize(input));

// Enter sends, Shift+Enter newline
input.addEventListener('keydown', (e) => {
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault();
    form.requestSubmit();
  }
});

form.addEventListener('submit', (e) => {
  e.preventDefault();
  const text = input.value.trim();
  if (!text) return;
  appendMessage({ text, sender: 'me', time: new Date() });
  input.value = '';
  autoresize(input);
  scrollMessagesToBottom();
  // … then send to backend or trigger reply
});
```

**MESSAGE BUILDER HELPER** (pure-JS DOM construction):
```javascript
function appendMessage({ text, sender = 'them', author, avatar, time = new Date(), readState }) {
  const msg = document.createElement('div');
  msg.className = 'msg ' + (sender === 'me' ? 'msg-sent' : 'msg-received');
  const stack = document.createElement('div');
  stack.className = 'msg-stack';
  if (sender !== 'me' && avatar) {
    const img = document.createElement('img');
    img.className = 'msg-avatar'; img.src = avatar; img.alt = '';
    msg.appendChild(img);
  }
  if (sender !== 'me' && author) {
    const a = document.createElement('div'); a.className = 'msg-author'; a.textContent = author;
    stack.appendChild(a);
  }
  const bubble = document.createElement('div');
  bubble.className = 'msg-bubble';
  bubble.textContent = text; // textContent prevents XSS
  stack.appendChild(bubble);
  const t = document.createElement('time');
  t.className = 'msg-time';
  t.textContent = time.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
  if (sender === 'me' && readState) {
    const rr = document.createElement('span');
    rr.className = 'read-receipt' + (readState === 'unread' ? ' unread' : '');
    rr.textContent = readState === 'unread' ? '✓' : '✓✓';
    t.appendChild(rr);
  }
  stack.appendChild(t);
  msg.appendChild(stack);
  document.getElementById('messages').appendChild(msg);
  scrollMessagesToBottom();
}
```

